1504→    private void throwIfConsumerGroupIsFull(
  1505→        ConsumerGroup group,
  1506→        String memberId
  1507→    ) throws GroupMaxSizeReachedException {
  1508→        // If the consumer group has reached its maximum capacity, the member is rejected if it is not
  1509→        // already a member of the consumer group.
  1510→        if (group.numMembers() >= config.consumerGroupMaxSize() && (memberId.isEmpty() || !group.hasMember(memberId))) {
  1511→            throw new GroupMaxSizeReachedException("The consumer group has reached its maximum capacity of "
  1512→                + config.consumerGroupMaxSize() + " members.");
  1513→        }
  1514→    }
  1515→
  1516→    /**
  1517→     * Checks whether the share group can accept a new member or not based on the
  1518→     * max group size defined.
  1519→     *
  1520→     * @param group     The share group.
  1521→     * @param memberId  The member id.
  1522→     *
  1523→     * @throws GroupMaxSizeReachedException if the maximum capacity has been reached.
  1524→     */
  1525→    private void throwIfShareGroupIsFull(
  1526→        ShareGroup group,
  1527→        String memberId
  1528→    ) throws GroupMaxSizeReachedException {
  1529→        // The member is rejected, if the share group has reached its maximum capacity, or it is not
  1530→        // a member of the share group.
  1531→        if (group.numMembers() >= config.shareGroupMaxSize() && (memberId.isEmpty() || !group.hasMember(memberId))) {
  1532→            throw new GroupMaxSizeReachedException("The share group has reached its maximum capacity of "
  1533→                + config.shareGroupMaxSize() + " members.");
  1534→        }
  1535→    }
  1536→
  1537→    /**
  1538→     * Checks whether the share group is empty.
  1539→     *
  1540→     * @param group     The share group.
  1541→     *
  1542→     * @throws GroupNotEmptyException if the group is not empty.
  1543→     */
  1544→    private void throwIfShareGroupIsNotEmpty(
  1545→        ShareGroup group
  1546→    ) throws GroupNotEmptyException {
  1547→        if (group.numMembers() > 0) {
  1548→            throw new GroupNotEmptyException(Errors.NON_EMPTY_GROUP.message());
  1549→        }
  1550→    }
  1551→
  1552→    /**
  1553→     * Validates the member epoch provided in the heartbeat request.
  1554→     *
  1555→     * @param member                The consumer group member.
  1556→     * @param receivedMemberEpoch   The member epoch.
