    context.sleep(sessionTimeoutMs - 1);

    // Still should be rejected (1ms before grace period)
    assertThrows(UnreleasedInstanceIdException.class, () ->
        context.consumerGroupHeartbeat(new ConsumerGroupHeartbeatRequestData()
            .setGroupId(groupId)
            .setMemberId(member2Id)
            .setMemberEpoch(0)
            .setInstanceId(instanceId)
            .setRebalanceTimeoutMs(60000)
            .setSubscribedTopicNames(List.of("test-topic"))
            .setTopicPartitions(List.of()))
    );

    // Advance time past grace period
    context.sleep(2); // Total: sessionTimeoutMs + 1

    // Now should be allowed to join with different member ID
    result = context.consumerGroupHeartbeat(new ConsumerGroupHeartbeatRequestData()
        .setGroupId(groupId)
        .setMemberId(member2Id)
        .setMemberEpoch(0)
        .setInstanceId(instanceId)
        .setRebalanceTimeoutMs(60000)
        .setSubscribedTopicNames(List.of("test-topic"))
        .setTopicPartitions(List.of()));

    assertEquals(1, result.response().memberEpoch());
    assertEquals(member2Id, result.response().memberId());
}
