            .setGroupId(groupId)
            .setMemberId(memberId)
            .setMemberEpoch(0)
            .setSubscribedTopicNames(List.of("test-topic")));

    int epoch1 = result.response().memberEpoch();
    assertEquals(1, epoch1);

    // Simulate target assignment change requesting revocation of [1,2]
    // (This would be triggered by assignor during updateTargetAssignment)

    // Send heartbeat with current epoch acknowledging partitions [0] (incomplete release)
    result = context.consumerGroupHeartbeat(new ConsumerGroupHeartbeatRequestData()
        .setGroupId(groupId)
        .setMemberId(memberId)
        .setMemberEpoch(epoch1)
        .setTopicPartitions(List.of(new ConsumerGroupHeartbeatRequestData.TopicPartitions()
            .setTopic("test-topic")
            .setPartitions(List.of(0)))));

    // Member still has partitions pending revocation
    ConsumerGroup group = context.groupMetadataManager.consumerGroup(groupId);
    ConsumerGroupMember member = group.member(memberId);
    assertTrue(!member.partitionsPendingRevocation().isEmpty());

    // Now member sends rejoin with epoch 0 (simulating network issue or client restart)
    result = context.consumerGroupHeartbeat(new ConsumerGroupHeartbeatRequestData()
        .setGroupId(groupId)
        .setMemberId(memberId)
        .setMemberEpoch(0)
        .setRebalanceTimeoutMs(60000)
        .setSubscribedTopicNames(List.of("test-topic"))
        .setTopicPartitions(List.of()));

